class TreeInfo {
    boolean isBST;
    int size;
    int minValue;
    int maxValue;

    TreeInfo(boolean isBST, int size, int minValue, int maxValue) {
        this.isBST = isBST;
        this.size = size;
        this.minValue = minValue;
        this.maxValue = maxValue;
    }
}

public int largestBSTSubtree(TreeNode root) {
    return largestBSTUtil(root, new int[1]).size;
}

private TreeInfo largestBSTUtil(TreeNode root, int[] largestBST) {
    if (root == null) return new TreeInfo(true, 0, Integer.MAX_VALUE, Integer.MIN_VALUE);

    TreeInfo left = largestBSTUtil(root.left, largestBST);
    TreeInfo right = largestBSTUtil(root.right, largestBST);

